namespace App\Http\Controllers;

use App\Models\User;
use Illuminate\Http\JsonResponse;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Auth;
use App\Http\Requests\UpdateUserRequest;

class UserController extends Controller
{
    /**
     * Update the authenticated user's profile.
     *
     * SECURITY NOTE: We do NOT use $request->all() because it exposes the application
     * to mass assignment vulnerabilities. An attacker could inject fields like:
     *   - is_admin: true
     *   - role: "superadmin"
     *   - email_verified_at: "2024-01-01"
     *   - password: "hacked"
     *
     * Instead, we explicitly validate and whitelist only the fields we expect.
     *
     * @param UpdateUserRequest $request
     * @return JsonResponse
     */
    public function update(UpdateUserRequest $request): JsonResponse
    {
        /** @var User $user */
        $user = Auth::user();

        // Only pick validated/allowed fields — never use $request->all()
        $validatedData = $request->validated();

        $user->update($validatedData);

        return response()->json([
            'message' => 'Profile updated successfully.',
            'user' => $user->fresh(),
        ]);
    }
}

